            "id": "actor-evm-caller",
            "name": "EVM Caller (Smart Contract / EOA)",
            "description": "Any smart contract or externally-owned account that invokes the p256verify precompile at address 0x100 via CALL/STATICCALL. This is an untrusted actor that supplies arbitrary 160-byte input to the precompile."
          },
          {
            "id": "actor-precompile",
            "name": "p256verify Precompile",
            "description": "The EIP-7951 precompile deployed at address 0x100, responsible for secp256r1 ECDSA signature verification. It is part of the trusted EVM execution environment."
          },
          {
            "id": "actor-evm-runtime",
            "name": "EVM Runtime / Execution Client",
            "description": "The Ethereum execution client (e.g. Geth, Nethermind, Besu, Reth) that implements the precompile. It is trusted to correctly implement the secp256r1 cryptographic operations and gas metering."
          },
          {
            "id": "actor-proposer",
            "name": "Block Proposer",
            "description": "A validator selected to propose a beacon block for a given slot. The proposer constructs the block including execution payload and blob KZG commitments. Proposers are economically incentivized via staking but are not unconditionally trusted."
          },
          {
            "id": "actor-validator",
            "name": "Beacon Chain Validator",
            "description": "A participant in the beacon chain consensus that attests to blocks and participates in justification/finalization. Validators collectively enforce protocol rules through attestation and slashing conditions."
          },
          {
            "id": "actor-execution-engine",
            "name": "Execution Engine",
            "description": "The execution-layer engine (Engine API endpoint) that verifies execution payloads. The beacon chain trusts this engine to validate payload consistency, including versioned hashes derived from blob KZG commitments."
          },
          {
            "id": "actor-network-peer",
            "name": "Network Peer",
            "description": "Any node participating in the peer-to-peer gossip network. Peers use fork digests for domain separation and topic subscription. They are untrusted and may attempt to inject messages from incompatible forks."
          },
          {
            "id": "actor-blob-scheduler",
            "name": "Blob Schedule Configuration",
            "description": "The protocol-level configuration (BLOB_SCHEDULE) that defines epoch-based blob parameter transitions. This is a governance/protocol actor whose entries are trusted as canonical once embedded in the consensus spec."
          }
        ],
        "trust_boundaries": [
          {
            "id": "tb-001",
            "from_actor": "actor-evm-caller",
            "to_actor": "actor-precompile",
            "description": "Untrusted EVM caller provides arbitrary calldata to the p256verify precompile. The precompile must safely handle any 160-byte (or non-160-byte) input without reverting. This is the primary attack surface for EIP-7951."
          },
          {
            "id": "tb-002",
            "from_actor": "actor-precompile",
            "to_actor": "actor-evm-caller",
            "description": "The precompile returns a result (32-byte success or empty bytes for failure) to the caller. The caller must correctly interpret the return value; a malicious or buggy caller may misinterpret empty output as success."
          },
          {
            "id": "tb-003",
            "from_actor": "actor-evm-runtime",
            "to_actor": "actor-precompile",
            "description": "The execution client provides gas context and calldata to the precompile. The precompile trusts the runtime for correct gas accounting and memory management."
          },
          {
            "id": "tb-004",
            "from_actor": "actor-proposer",
            "to_actor": "actor-validator",
            "description": "The proposer submits a beacon block (including execution payload and blob commitments) to validators. Validators must independently verify all assertions (parent hash chain, randao, timestamp, blob count limits) and reject invalid blocks."
          },
          {
            "id": "tb-005",
            "from_actor": "actor-proposer",
            "to_actor": "actor-execution-engine",
            "description": "The proposer's execution payload is forwarded to the execution engine via verify_and_notify_new_payload. The execution engine is trusted to correctly validate payload consistency and state transitions."
          },
          {
            "id": "tb-006",
            "from_actor": "actor-execution-engine",
            "to_actor": "actor-validator",
            "description": "The execution engine returns a validity verdict to the consensus layer. Validators trust this verdict to determine whether the execution payload is valid. A compromised execution engine could cause validators to accept invalid state transitions."
          },
          {
            "id": "tb-007",
            "from_actor": "actor-network-peer",
            "to_actor": "actor-validator",
            "description": "Network peers exchange messages on gossip topics identified by fork digests. The fork digest (now incorporating blob parameters via EIP-7892) acts as a domain separator. Peers from incompatible configurations should be automatically segregated."
          },
          {
            "id": "tb-008",
            "from_actor": "actor-blob-scheduler",
            "to_actor": "actor-validator",
            "description": "The BLOB_SCHEDULE configuration determines maximum blob counts per epoch. Validators must correctly look up the schedule to enforce blob limits. Misconfigured or divergent schedules between clients would cause consensus failures."
          },
          {
            "id": "tb-009",
            "from_actor": "actor-validator",
            "to_actor": "actor-validator",
            "description": "Validators rely on the proposer_lookahead state field (EIP-7917) to know future proposers. This pre-computation means all validators can predict upcoming proposers, creating a trade-off between protocol efficiency and proposer privacy."
          }
        ],
        "assumptions": [
          {
            "id": "asm-001",
            "text": "The secp256r1 curve parameters (field modulus p, subgroup order n, base point G, cofactor 1) as defined in NIST SP 800-186 are correct and cryptographically secure."
          },
          {
            "id": "asm-002",
            "text": "The p256verify precompile implementation performs mathematically correct modular arithmetic, scalar multiplication, and point addition over the secp256r1 group. Bugs in these operations could cause consensus splits between clients."
          },
          {
            "id": "asm-003",
            "text": "Constant-time execution is NOT guaranteed by EIP-7951. The spec explicitly states that implementations are not required to use constant-time algorithms, meaning timing side-channels may leak information about private keys to co-located observers."
          },
          {
            "id": "asm-004",
            "text": "The precompile MUST NOT revert under any circumstances (except out-of-gas). Invalid inputs return empty bytes rather than causing a revert, ensuring callers can always handle failure gracefully."
          },
          {
            "id": "asm-005",
            "text": "The fixed gas cost of 6900 is assumed to be sufficient to prevent the precompile from being used as a denial-of-service vector. The gas cost must cover worst-case computational complexity across all client implementations."
          },
          {
            "id": "asm-006",
            "text": "Input validation checks MUST be performed in a specific sequential order (length, r bounds, s bounds, qx bounds, qy bounds, curve equation, infinity check) to ensure deterministic behavior across all client implementations."
          },
          {
            "id": "asm-007",
            "text": "The point-at-infinity check on R' during signature verification is mandatory (fixes RIP-7212 vulnerability). Omitting this check leads to implementation-dependent non-deterministic behavior."
          },
          {
            "id": "asm-008",
            "text": "The signature comparison must use modular reduction (r' == r mod n) rather than direct equality (fixes RIP-7212 vulnerability). Direct comparison fails for edge-case x-coordinates exceeding the subgroup order."
          },
          {
            "id": "asm-009",
            "text": "The execution engine (Engine API) is assumed to be a trusted, correct component that faithfully validates execution payloads. A bug or compromise in the execution engine bypasses all consensus-layer protections."
          },
          {
            "id": "asm-010",
            "text": "BLOB_SCHEDULE entries are assumed to have unique, monotonically meaningful epoch values, all >= FULU_FORK_EPOCH. Duplicate or out-of-order entries could cause ambiguous blob parameter resolution."
          },
          {
            "id": "asm-011",
            "text": "All execution clients implement identical BLOB_SCHEDULE configurations. Divergent schedules between clients would cause consensus failures at the epoch boundaries where blob parameters change."
          },
          {
            "id": "asm-012",
            "text": "The proposer lookahead (EIP-7917) shifts correctly at epoch boundaries, maintaining exactly (MIN_SEED_LOOKAHEAD + 1) * SLOTS_PER_EPOCH entries. Off-by-one errors in the shift operation could assign wrong proposers."
          },
          {
            "id": "asm-013",
            "text": "The fork digest XOR with blob parameter hash (EIP-7892) provides sufficient domain separation to prevent cross-fork message confusion. The 4-byte truncation is assumed to have negligible collision probability for practical configurations."
          },
          {
            "id": "asm-014",
            "text": "The epoch processing pipeline (15 sequential sub-processes) must execute in strict order. State mutations from earlier steps are visible to later steps, and reordering would produce incorrect state transitions."
          },
          {
            "id": "asm-015",
            "text": "Proposer indices are deterministically derived from the seed, active validator set, and slot. All honest validators compute identical proposer assignments given the same state."
          }
        ],
        "stride_analysis": [
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Spoofing",
            "description": "An attacker could submit a forged signature (h, r, s) with a valid public key (qx, qy) to the precompile, attempting to impersonate the key holder. If the precompile has a bug in validation or verification logic, it could accept an invalid signature as valid.",
            "mitigation": "The precompile implements comprehensive input validation (SG-002) and standard ECDSA verification (SG-003) including the RIP-7212 vulnerability fixes (point-at-infinity check, modular comparison). Callers must still verify the returned value is 0x01."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Tampering",
            "description": "A malicious caller could craft inputs that exploit edge cases in the secp256r1 arithmetic: zero-value r or s, points not on the curve, the point at infinity, or field elements exceeding the modulus. These could trigger undefined behavior in buggy implementations.",
            "mitigation": "Sequential input validation (SG-002) rejects out-of-range r/s values, out-of-range coordinates, off-curve points, and the point at infinity before verification begins. The ordered validation ensures deterministic rejection across all client implementations."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Denial of Service",
            "description": "An attacker could invoke the precompile repeatedly with crafted inputs designed to maximize computational cost, attempting to slow block processing. Since gas is fixed at 6900 regardless of execution path, inputs that fail early validation consume the same gas as successful verifications.",
            "mitigation": "The fixed 6900 gas cost (SG-006) prevents gas-based DoS by ensuring callers always pay the full cost. However, if the actual worst-case computation exceeds what 6900 gas represents, it could create an underpriced operation exploitable for resource exhaustion."
          },
          {
            "trust_boundary_id": "tb-001",
            "threat_type": "Information Disclosure",
            "description": "Since EIP-7951 explicitly does NOT require constant-time implementation, a co-located attacker (e.g., on the same physical machine as a validator) could perform timing side-channel attacks to extract information about the private key from the precompile's execution time variations.",
            "mitigation": "No protocol-level mitigation. The specification acknowledges this by not mandating constant-time operations. Mitigation is left to individual client implementations and deployment hardening. This is a known trade-off favoring performance over side-channel resistance."
          },
          {
            "trust_boundary_id": "tb-002",
            "threat_type": "Tampering",
            "description": "A smart contract caller could misinterpret the precompile's return value. The precompile returns empty bytes (0 bytes) on failure and 0x01 (32 bytes) on success. A buggy caller that checks only the return status (success/fail) of the CALL opcode rather than the returned data would incorrectly treat all non-reverting calls as successful signature verifications.",
            "mitigation": "Callers must explicitly check the returned data length (32 bytes) and value (0x01). The precompile's no-revert invariant (INV-001 in SG-001) means CALL always succeeds; the signature validity is encoded solely in the return data. Wallet and contract developers must be educated about this pattern."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Tampering",
            "description": "If different execution clients implement the secp256r1 arithmetic differently (e.g., different bignum libraries, different point multiplication algorithms), they could produce divergent results for edge-case inputs, causing a consensus split.",
            "mitigation": "The specification defines precise validation ordering (SG-002), exact byte layouts (SG-005), and specific vulnerability fixes (SG-003 INV-002, INV-003). Cross-client test vectors should be developed and validated. The ordered validation sequence is critical for determinism."
          },
          {
            "trust_boundary_id": "tb-003",
            "threat_type": "Elevation of Privilege",
            "description": "A bug in the precompile implementation could allow an attacker to forge secp256r1 signatures, potentially enabling unauthorized actions in smart contracts that rely on P256 for access control (e.g., WebAuthn/Passkey-based wallets, HSM-backed authentication).",
            "mitigation": "The specification includes explicit fixes for known RIP-7212 vulnerabilities: mandatory point-at-infinity check on R' (SG-003 INV-002) and modular comparison r' == r (mod n) instead of direct equality (SG-003 INV-003). Rigorous testing against NIST test vectors is essential."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Tampering",
            "description": "A malicious proposer could construct a block with an execution payload whose parent_hash does not chain correctly, whose timestamp is inconsistent, or whose blob commitment count exceeds the current epoch's limit from BLOB_SCHEDULE.",
            "mitigation": "Validators independently verify all payload assertions (SG-002 in Fulu beacon chain): parent hash chaining (INV-001), randao consistency (INV-002), timestamp correctness (INV-003), and blob count limits via get_blob_parameters (INV-004). Invalid blocks are rejected by attestation."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Denial of Service",
            "description": "A proposer could include the maximum allowed blob commitments (up to 21 after the second BLOB_SCHEDULE increase) to maximize block processing time. As blob limits increase via EIP-7892 without requiring a hard fork, a sudden increase could strain unprepared validators.",
            "mitigation": "The BLOB_SCHEDULE defines maximum blob counts per epoch, and validators enforce these limits. The schedule is embedded in the consensus spec so all clients know the limits in advance. However, the dynamic nature of blob-only parameter changes means client operators must update configurations at epoch boundaries."
          },
          {
            "trust_boundary_id": "tb-004",
            "threat_type": "Spoofing",
            "description": "A malicious entity could attempt to propose blocks for slots they are not assigned to. With EIP-7917's proposer lookahead, all participants know future proposers, making slot-stealing detectable but also making legitimate proposers targetable.",
            "mitigation": "Proposer selection is deterministic and verifiable by all validators via the proposer_lookahead state field (SG-005). Blocks from unauthorized proposers are rejected during attestation. The deterministic seed derivation (SG-004) ensures all honest validators agree on the assignment."
          },
          {
            "trust_boundary_id": "tb-005",
            "threat_type": "Tampering",
            "description": "If the execution engine is compromised or buggy, it could accept invalid execution payloads (e.g., invalid state root, incorrect gas calculations, tampered transaction results). The consensus layer delegates payload validation entirely to the execution engine.",
            "mitigation": "The consensus layer verifies structural properties (parent hash, randao, timestamp, blob counts) before forwarding to the execution engine (SG-002 in Fulu beacon chain). However, semantic validation of the execution payload state transition is entirely trusted to the execution engine. Multi-client diversity is the primary mitigation."
          },
          {
            "trust_boundary_id": "tb-006",
            "threat_type": "Repudiation",
            "description": "The execution engine returns a boolean validity verdict for payloads. If the engine's verdict is incorrect (either false positive or false negative), there is limited ability to audit or repudiate the decision after the fact, as the execution engine's internal state is not directly observable by the consensus layer.",
            "mitigation": "Multi-client execution environments provide implicit redundancy. If one execution engine produces different results from others, the consensus mechanism will naturally fork, and the majority-correct chain will be finalized. Post-hoc analysis tools can replay execution payloads."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Spoofing",
            "description": "A network peer on an incompatible fork (different blob parameters) could attempt to inject messages into gossip topics. Without proper fork digest domain separation, validators could process messages from incompatible protocol versions.",
            "mitigation": "The fork digest now incorporates blob parameters via XOR with hash(epoch + max_blobs_per_block) (SG-003 in Fulu beacon chain). This ensures different blob configurations produce different fork digests, automatically segregating peers with incompatible parameters on the gossip network."
          },
          {
            "trust_boundary_id": "tb-007",
            "threat_type": "Denial of Service",
            "description": "A malicious peer could flood the gossip network with messages using valid fork digests but invalid content, forcing validators to expend resources validating and rejecting them.",
            "mitigation": "Standard gossip protocol rate limiting and peer scoring mechanisms apply. The fork digest serves only as a first filter for topic subscription; full message validation still occurs. Persistent offenders are deprioritized via peer scoring."
          },
          {
            "trust_boundary_id": "tb-008",
            "threat_type": "Tampering",
            "description": "If a client implementation has an incorrect BLOB_SCHEDULE configuration (wrong epoch values, wrong max_blobs_per_block, or missing entries), it would compute different blob parameter limits than other clients, causing the node to reject valid blocks or accept invalid ones, effectively forking itself off the network.",
            "mitigation": "The BLOB_SCHEDULE is defined in the consensus spec and must be identical across all client implementations. The fallback to ELECTRA parameters when no schedule entry matches (SG-001 INV-004) provides a safe default. However, the dynamic scheduling mechanism (EIP-7892) requires careful coordination for each parameter change."
          },
          {
            "trust_boundary_id": "tb-009",
            "threat_type": "Information Disclosure",
            "description": "The proposer lookahead (EIP-7917) makes future block proposers known to all network participants up to MIN_SEED_LOOKAHEAD + 1 epochs in advance. This enables targeted attacks against known future proposers: DDoS attacks to prevent them from proposing, MEV-related front-running, or social engineering.",
            "mitigation": "This is an explicit design trade-off in EIP-7917, favoring protocol simplicity and efficiency over proposer privacy. Proposers can use infrastructure protections (DDoS mitigation, private relay networks). The lookahead period is bounded to limit the attack window. Single-secret leader election (SSLE) remains a long-term research direction."
          },
          {
            "trust_boundary_id": "tb-009",
            "threat_type": "Denial of Service",
            "description": "An adversary who knows the next proposer from the lookahead could launch a targeted DDoS attack against that proposer's infrastructure, causing them to miss their slot and the network to skip a block.",
            "mitigation": "Proposers can use resilient infrastructure, VPNs, and relay networks. Missed slots are handled gracefully by the protocol (the chain simply skips to the next slot). The economic cost of staking provides some deterrent against proposer attacks. The bounded lookahead period limits advance planning time for attackers."
          },
          {
            "trust_boundary_id": "tb-009",
            "threat_type": "Elevation of Privilege",
            "description": "If the proposer_lookahead shift operation (SG-008) contains an off-by-one error or the epoch computation is incorrect, a validator could be incorrectly assigned proposer duties, gaining the privilege to propose blocks in slots not legitimately theirs.",
            "mitigation": "The proposer_lookahead update logic (SG-008) uses explicit offset calculations and is part of the epoch processing pipeline. All validators compute identical lookahead state deterministically. An implementation bug would manifest as a consensus split, detectable through multi-client testing."
          }
        ]
      },
      "_source_file": "outputs/01d_PARTIAL_W0B1_1770284080.json"
    }
  ],
  "total_items": 1
}

